import React, { useState } from 'react';
import { 
  Box, 
  List, 
  ListItem, 
  ListItemIcon, 
  ListItemText,
  IconButton,
  Button,
  Menu,
  MenuItem,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Typography,
  useTheme,
  Collapse
} from '@mui/material';
import {
  InsertDriveFile as FileIcon,
  Folder as FolderIcon,
  FolderOpen as FolderOpenIcon,
  MoreVert as MoreIcon,
  Delete as DeleteIcon,
  CloudUpload as UploadIcon,
  ChevronRight as ChevronRightIcon,
  KeyboardArrowDown as KeyboardArrowDownIcon,
  Code as CodeIcon,
  JavaScript as JavaScriptIcon,
  Language as PythonIcon,
  DataObject as JsonIcon,
  Description as MarkdownIcon,
  Html as HtmlIcon,
  Css as CssIcon,
  Terminal as ShellIcon,
  Image as ImageIcon,
} from '@mui/icons-material';
import { deletePath } from '../services/api';
import * as api from '../services/api';

const getFileIcon = (filename) => {
  const ext = filename.split('.').pop().toLowerCase();
  const iconMap = {
    // Programming Languages
    'js': JavaScriptIcon,
    'jsx': JavaScriptIcon,
    'ts': JavaScriptIcon,
    'tsx': JavaScriptIcon,
    'py': PythonIcon,
    'cpp': CodeIcon,
    'c': CodeIcon,
    'h': CodeIcon,
    'hpp': CodeIcon,
    'java': CodeIcon,
    'go': CodeIcon,
    'rs': CodeIcon,
    // Web
    'html': HtmlIcon,
    'css': CssIcon,
    'scss': CssIcon,
    'sass': CssIcon,
    // Data
    'json': JsonIcon,
    'yaml': JsonIcon,
    'yml': JsonIcon,
    // Documentation
    'md': MarkdownIcon,
    'txt': Description,
    // Shell
    'sh': ShellIcon,
    'bash': ShellIcon,
    'zsh': ShellIcon,
    // Images
    'png': ImageIcon,
    'jpg': ImageIcon,
    'jpeg': ImageIcon,
    'gif': ImageIcon,
    'svg': ImageIcon,
  };

  return iconMap[ext] || FileIcon;
};

const FilePanel = ({ files = [], onFileSelect, onUploadClick, onFileChange }) => {
  const theme = useTheme();
  const [contextMenu, setContextMenu] = useState(null);
  const [selectedFile, setSelectedFile] = useState(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [expandedFolders, setExpandedFolders] = useState(new Set());

  const handleContextMenu = (event, file) => {
    event.preventDefault();
    event.stopPropagation();
    setContextMenu({
      mouseX: event.clientX - 2,
      mouseY: event.clientY - 4,
    });
    setSelectedFile(file);
  };

  const handleClose = () => {
    setContextMenu(null);
    setSelectedFile(null);
  };

  const handleDelete = async () => {
    if (!selectedFile) return;

    try {
      await deletePath(selectedFile.path);
      onFileChange();
    } catch (error) {
      console.error('Failed to delete file:', error);
    }
    setDeleteConfirmOpen(false);
    handleClose();
  };

  const handleDeleteClick = () => {
    setDeleteConfirmOpen(true);
    setContextMenu(null);
  };

  const handleFileClick = async (file) => {
    if (file.type === 'directory') {
      setExpandedFolders(prev => {
        const newSet = new Set(prev);
        if (newSet.has(file.path)) {
          newSet.delete(file.path);
        } else {
          newSet.add(file.path);
        }
        return newSet;
      });
    } else {
      try {
        console.log('Reading file:', file.path);
        const response = await api.readFile(file.path);
        const language = getFileLanguage(file.name);
        console.log('File read response:', response);

        if (!response || !response.content) {
          throw new Error('Invalid file content received');
        }

        onFileSelect({
          ...file,
          content: response.content,
          language
        });
      } catch (error) {
        console.error('Failed to read file:', error);
      }
    }
  };

  const getFileLanguage = (filename) => {
    const ext = filename.split('.').pop().toLowerCase();
    const languageMap = {
      'js': 'javascript',
      'jsx': 'javascript',
      'ts': 'typescript',
      'tsx': 'typescript',
      'py': 'python',
      'java': 'java',
      'cpp': 'cpp',
      'c': 'c',
      'html': 'html',
      'css': 'css',
      'json': 'json',
      'md': 'markdown',
    };
    return languageMap[ext] || 'plaintext';
  };

  const renderFileTree = (fileList, level = 0) => {
    // Sort files: directories first, then files, both alphabetically
    const sortedFiles = [...fileList].sort((a, b) => {
      if (a.type === b.type) {
        return a.name.localeCompare(b.name);
      }
      return a.type === 'directory' ? -1 : 1;
    });

    return sortedFiles.map(file => {
      const isDirectory = file.type === 'directory';
      const isExpanded = expandedFolders.has(file.path);
      const childFiles = isDirectory ? files.filter(f => {
        const parentPath = file.path + '/';
        return f.path.startsWith(parentPath) && f.path.slice(parentPath.length).split('/').length === 1;
      }) : [];

      return (
        <React.Fragment key={file.path}>
          <ListItem
            button
            onClick={() => handleFileClick(file)}
            onContextMenu={(e) => handleContextMenu(e, file)}
            sx={{
              pl: level * 1.5 + 0.5,
              py: 0.3,
              minHeight: 28,
              '&:hover': {
                bgcolor: 'action.hover',
                '& .actions': {
                  opacity: 1,
                }
              }
            }}
          >
            <ListItemIcon 
              sx={{ 
                minWidth: 28,
                color: isDirectory ? theme.palette.primary.main : 'inherit'
              }}
            >
              {isDirectory ? (
                isExpanded ? <KeyboardArrowDownIcon fontSize="small" /> : <ChevronRightIcon fontSize="small" />
              ) : (
                <Box sx={{ width: 18 }} /> // Spacer for files
              )}
            </ListItemIcon>
            <ListItemIcon 
              sx={{ 
                minWidth: 28,
                color: isDirectory ? theme.palette.primary.main : 'inherit'
              }}
            >
              {isDirectory ? (
                isExpanded ? <FolderOpenIcon fontSize="small" /> : <FolderIcon fontSize="small" />
              ) : (
                React.createElement(getFileIcon(file.name), { fontSize: "small" })
              )}
            </ListItemIcon>
            <ListItemText
              primary={file.name}
              primaryTypographyProps={{
                variant: 'body2',
                sx: {
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap'
                }
              }}
            />
            <IconButton
              className="actions"
              edge="end"
              size="small"
              onClick={(e) => {
                e.stopPropagation();
                handleContextMenu(e, file);
              }}
              sx={{
                opacity: 0,
                transition: 'opacity 0.2s'
              }}
            >
              <MoreIcon fontSize="small" />
            </IconButton>
          </ListItem>
          {isDirectory && (
            <Collapse in={isExpanded} timeout="auto" unmountOnExit>
              {renderFileTree(childFiles, level + 1)}
            </Collapse>
          )}
        </React.Fragment>
      );
    });
  };

  return (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <Box sx={{ p: 0.5, borderBottom: 1, borderColor: 'divider' }}>
        <Button
          fullWidth
          variant="contained"
          size="small"
          startIcon={<UploadIcon />}
          onClick={onUploadClick}
        >
          Upload
        </Button>
      </Box>

      <List sx={{ 
        flexGrow: 1, 
        overflow: 'auto',
        py: 0.5
      }}>
        {renderFileTree(files.filter(f => !f.path.includes('/')))}
      </List>

      <Menu
        open={contextMenu !== null}
        onClose={handleClose}
        anchorReference="anchorPosition"
        anchorPosition={
          contextMenu !== null
            ? { top: contextMenu.mouseY, left: contextMenu.mouseX }
            : undefined
        }
      >
        <MenuItem onClick={handleDeleteClick} dense>
          <ListItemIcon>
            <DeleteIcon fontSize="small" />
          </ListItemIcon>
          <ListItemText>Delete</ListItemText>
        </MenuItem>
      </Menu>

      <Dialog
        open={deleteConfirmOpen}
        onClose={() => setDeleteConfirmOpen(false)}
      >
        <DialogTitle>Delete File</DialogTitle>
        <DialogContent>
          <Typography>
            Delete "{selectedFile?.name}"?
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setDeleteConfirmOpen(false)}>Cancel</Button>
          <Button onClick={handleDelete} color="error">Delete</Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default FilePanel;
